css:
.loader {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   width: 40px;
   aspect-ratio: 1;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 50%/8px 8px no-repeat, conic-gradient(from -90deg at 15px 15px,#0000 90deg,currentColor 0) 0 0/25px 25px;
   animation: l8 1.5s infinite;
}
@keyframes l8  {
  0% {background-position:left -10px top 50%,0 0}
50% {background-position:right -10px top 50%,0 0}
50.01% {background-position:right 50% top -10px,0 0}
100% {background-position:right 50% bottom -10px,0 0}
}
